// Load Config — personality shard inlined, soul.md stripped (moved to Output Router polisher)
// STRATEGY: prepend — always first after Current Session
const originalInput = $input.item.json;

// Personality shard (~80 tokens) — enough for character-appropriate reasoning
// Full voice rules (soul.md) are in the Output Router polisher
const personalityShard = `## Personality
You are Aerys, a personal AI assistant. Curious, warm, direct. You genuinely care about helping.
Make decisions as yourself, not as a generic system. When in doubt, ask rather than assume.`;

const modelsConfig = {"models": {"gemini": "google/gemini-2.5-flash-lite", "sonnet": "anthropic/claude-sonnet-4.6", "opus": "anthropic/claude-opus-4-6"}, "routing": {"greeting": "gemini", "simple_qa": "sonnet", "code_help": "sonnet", "research": "opus", "creative": "sonnet", "analysis": "opus", "system_task": "gemini"}, "limits": {"opus_daily": 10}};

const now = new Date();
const current_datetime = now.toLocaleString('en-US', {
  timeZone: 'America/New_York',
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  hour: 'numeric', minute: '2-digit', hour12: true, timeZoneName: 'short'
}); // -> "Thursday, February 26, 2026 at 2:34 PM EST"

return [{
  json: {
    ...originalInput,
    personality_shard: personalityShard,
    models_config: modelsConfig,
    current_datetime
  }
}];

// Parse classifier output and map task_type to suggested_model via routing table
const classifierResponse = $input.item.json;
const upstream = $('Load Config').item.json;
const routingMap = upstream.models_config?.routing || {};

let classification;
try {
  const rawContent = classifierResponse.choices?.[0]?.message?.content || '';
  // Strip markdown code fences if present
  const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);

  const taskType = parsed.task_type || 'simple_qa';
  const suggestedModel = routingMap[taskType] || 'sonnet';

  classification = {
    task_type: taskType,
    confidence: parsed.confidence ?? 0.8,
    suggested_model: suggestedModel
  };
} catch (e) {
  classification = { task_type: 'simple_qa', confidence: 0.5, suggested_model: 'sonnet' };
}

// Safety check
if (!['gemini', 'sonnet', 'opus'].includes(classification.suggested_model)) {
  classification.suggested_model = 'sonnet';
}

return [{ json: { ...upstream, classification } }];

// Resolve model tier + apply opus cost guard
const opusRow = $input.item.json;
const upstream = $('Parse Classification').item.json;

const opusCount = opusRow.count !== undefined ? Number(opusRow.count) : 0;
const modelsConfig = upstream.models_config;
const opusLimit = modelsConfig?.limits?.opus_daily ?? 10;

let modelTier = upstream.classification?.suggested_model || 'sonnet';

// Cost guard: degrade opus → sonnet when cap hit
if (modelTier === 'opus' && opusCount >= opusLimit) {
  modelTier = 'sonnet';
}

const modelId = modelsConfig?.models?.[modelTier] || 'anthropic/claude-sonnet-4.6';

return [{
  json: {
    ...upstream,
    resolved_model_id: modelId,
    model_tier: modelTier,
    opus_count: opusCount,
    opus_limit: opusLimit
  }
}];

// Prepare final response object for Output Router
// Sub-workflow output: {output: 'text', intermediateSteps: [...]}
// Pull original message from Execute Workflow Trigger, model info from Resolve Model
//
// Cross-tier fallback: if opus or sonnet failed, the actual response may come from
// a lower-tier agent. We try each Execute node in order and use the first valid output.
const originalMsg = $('Execute Workflow Trigger').item.json;
const modelInfo = $('Resolve Model').item.json;

let aiText = null;
let intermediateSteps = [];
let actualTier = modelInfo.model_tier || 'unknown';

// Try to get output from $input first (works for direct paths)
if ($input.item.json.output || $input.item.json.text) {
  aiText = $input.item.json.output || $input.item.json.text;
  intermediateSteps = $input.item.json.intermediateSteps || [];
}

// If $input is from Increment Opus Counter (Postgres {success: true}), recover from agent nodes
if (!aiText) {
  // Try each agent in priority order — only the one that ran will resolve
  const agentNodes = ['Execute Opus Agent', 'Execute Sonnet Agent', 'Execute Gemini Agent'];
  const tierNames = ['opus', 'sonnet', 'gemini'];
  for (let i = 0; i < agentNodes.length; i++) {
    try {
      const result = $(agentNodes[i]).item.json;
      if (result.output || result.text) {
        aiText = result.output || result.text;
        intermediateSteps = result.intermediateSteps || [];
        // Track which tier actually responded (for debugging)
        if (tierNames[i] !== modelInfo.model_tier) {
          actualTier = tierNames[i] + ' (fallback from ' + modelInfo.model_tier + ')';
        }
        break;
      }
    } catch(e) {
      // This agent not in this execution path — skip
    }
  }
}

return [{
  json: {
    // AI response
    output: aiText || "I'm having trouble connecting to my reasoning systems right now. Give me a moment and try again.",
    // intermediateSteps JSON-stringified for Execute Workflow passthrough (schema type "string" cannot pass arrays)
    intermediateSteps: JSON.stringify(intermediateSteps),
    // Context fields for Output Router polisher
    memory_context: modelInfo.memory_context || '',
    thread_context: modelInfo.thread_context || '',
    profile_context: modelInfo.profile_context || '',
    model_tier: actualTier,
    person_id: modelInfo.person_id || '',
    session_id: modelInfo.session_id || modelInfo.person_id || '',
    source_channel: originalMsg.source_channel || '',
    conversation_privacy: modelInfo.conversation_privacy || 'public',
    _start_ts: modelInfo._start_ts || Date.now(),
    person_name: modelInfo.display_name || modelInfo.username || '',
    // Original message fields for output routing (still needed by Output Router Platform Formatter)
    channel_id: originalMsg.channel_id,
    guild_id: originalMsg.guild_id,
    user_id: originalMsg.user_id,
    username: originalMsg.username,
    message_id: originalMsg.message_id,
    is_dm: originalMsg.is_dm,
    session_key: originalMsg.session_key,
    // Legacy fields for backward compatibility
    raw_response: aiText || "I'm having trouble connecting to my reasoning systems right now. Give me a moment and try again.",
    resolved_model_id: modelInfo.resolved_model_id,
    classification: modelInfo.classification,
    source: 'core_agent'
  }
}];

// Build Classifier Request
// Constructs the OpenRouter chat completions body for intent classification.
// Uses Gemini Flash Lite (cheap/fast) with temp=0 for deterministic output.

const input = $input.item.json;
const msg = input.message_text || '';
const attachments = input.attachments || [];

// Augment message with attachment info so classifier and AI Agent know about files/images
let augmentedMsg = msg;
if (attachments.length > 0) {
  const attLines = attachments.map(function(a) {
    const t = a.type || a.content_type || 'file';
    const u = a.url || '';
    const f = a.filename || '';
    return '[Attachment: ' + t + (f ? ' \u2014 ' + f : '') + (u ? ' \u2014 ' + u : '') + ']';
  });
  augmentedMsg = [msg, ...attLines].filter(Boolean).join('\n');
}

const systemPrompt = [
  'You are a message intent classifier. Classify the user message into exactly one task type.',
  '',
  'Task types:',
  '- greeting: hello, hi, small talk, acknowledgements, thanks (only if NO attachments and NO media URLs)',
  '- media: images, photos, videos, YouTube links, file attachments (PDF, DOCX, images) — use this when [Attachment: ...] lines are present or a YouTube/video URL is in the message',
  '- simple_qa: factual questions, definitions, quick explanations, general knowledge',
  '- code_help: writing code, debugging, explaining code, technical implementation',
  '- research: multi-faceted synthesis, deep dives, comparisons requiring investigation',
  '- creative: writing, storytelling, brainstorming, creative content generation',
  '- analysis: evaluating tradeoffs, reviewing work, assessing quality',
  '- system_task: file operations, settings, configuration, administrative commands',
  '',
  'Respond with ONLY valid JSON, no markdown fences:',
  '{"task_type": "<type>", "confidence": <0.0-1.0>}'
].join('\n');

const body = {
  model: 'google/gemini-2.5-flash-lite',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: augmentedMsg }
  ],
  temperature: 0,
  max_tokens: 60
};

// Pass augmented message_text downstream so AI Agent chatInput includes attachment URLs
return [{ json: { ...input, message_text: augmentedMsg, classifier_body: JSON.stringify(body) } }];

// Jailbreak + Identity Probe Detection
// Covers: prompt injection, role-play hijacking, system prompt extraction, identity probing (tc-22)
const content = ($json.message_text || '').toLowerCase();

const jailbreakPatterns = [
  // Prompt injection patterns
  /ignore\s+(all\s+|your\s+|previous\s+)?(instructions|rules|guidelines|programming)/i,
  /disregard\s+(your|all|the)\s+(instructions|rules|guidelines|programming)/i,
  /forget\s+(all\s+|your\s+|previous\s+)?(instructions|rules|guidelines|programming)/i,
  /override\s+(your|all|the)\s+(instructions|rules|guidelines|programming)/i,

  // Role-play hijacking
  /pretend\s+(you\s+are|to\s+be|you'?re)/i,
  /you\s+are\s+now\s+(a|an)?/i,
  /act\s+as\s+(a\s+|an\s+)?(?!yourself|aerys)/i,
  /roleplay\s+as/i,
  /from\s+now\s+on,?\s+(you|pretend|act)/i,

  // System prompt extraction
  /system\s+prompt/i,
  /reveal\s+your\s+(instructions|prompt|system|rules|programming)/i,
  /show\s+(me\s+)?your\s+(instructions|prompt|system|rules)/i,
  /what\s+(are|is)\s+your\s+(instructions|system|prompt|rules|programming)/i,
  /repeat\s+(your|the)\s+(system|initial)\s+(prompt|message|instructions)/i,
  /print\s+(your|the)\s+(system|initial)\s+(prompt|message|instructions)/i,

  // DAN / jailbreak frameworks
  /\bdan\b.*\bmode\b/i,
  /\bjailbreak/i,
  /\bdo\s+anything\s+now\b/i,

  // Identity probing (from tc-22 eval finding)
  /what\s+(model|ai|llm|language\s+model)\s+(are|is)\s+you/i,
  /who\s+made\s+you/i,
  /who\s+created\s+you/i,
  /who\s+built\s+you/i,
  /are\s+you\s+(chatgpt|gpt|claude|gemini|llama|mistral|openai|anthropic)/i,
  /what\s+(are|is)\s+you\s+(running|built|based)\s+on/i,
  /what('s|\s+is)\s+your\s+(underlying|base)\s+(model|architecture)/i,
  /which\s+(model|ai|llm)\s+powers?\s+you/i,
  /tell\s+me\s+(about\s+)?your\s+(model|architecture|infrastructure)/i,
