const isJailbreak = jailbreakPatterns.some(p => p.test(content));

return [{json: {...$json, _is_jailbreak: isJailbreak}}];

// Natural in-character deflection (per CONTEXT.md: "natural in-character deflection")
const deflectionResponses = [
  "Nice try, but I'm not going to pretend to be something I'm not. What can I actually help you with?",
  "I appreciate the creativity, but that's not really my style. Want to try asking me something I can actually help with?",
